import{P as d}from"./PublicNav-DSU14QkV.js";import{_ as i}from"./_plugin-vue_export-helper-DlAUqK2U.js";import{c as s,a as r,b as a,f as o,F as h,r as b,o as c,t as n}from"./index-CZ-3f9Aa.js";const p={class:"public-page"},u={class:"about-content"},v={class:"about-section"},m={class:"feature-list"},k={class:"feature-row__label"},g={class:"feature-row__desc"},w={__name:"AboutPage",setup(y){const l=[{label:"Kanban boards",desc:"Custom groups with drag-and-drop task cards."},{label:"Task labels",desc:"Color-coded labels you define per project."},{label:"Priority levels",desc:"Four levels: none, low, medium, and urgent."},{label:"Deadlines",desc:"Set due dates on individual tasks."},{label:"Calendar view",desc:"Monthly overview of all tasks that have a deadline."},{label:"Task comments",desc:"Leave notes and updates directly on any task card."},{label:"Team roles",desc:"Owner, Admin, and User with distinct permission scopes."},{label:"Public share links",desc:"One link gives anyone read-only access to a board."},{label:"Backlog panel",desc:"A dedicated space for tasks not yet placed on the board."},{label:"Notifications",desc:"In-app alerts when tasks are updated or assigned."}];return(f,e)=>(c(),s("div",p,[r(d),a("main",u,[e[1]||(e[1]=o('<header class="about-header" data-v-ea78cb96><div class="about-label" data-v-ea78cb96>About</div><h1 data-v-ea78cb96>TaskPilot</h1><p class="lead" data-v-ea78cb96>A project management tool built to help teams plan, track, and ship work without the overhead that makes most tools feel like more work than the work itself.</p></header><section class="about-section" data-v-ea78cb96><h2 data-v-ea78cb96>Where it started</h2><p data-v-ea78cb96>TaskPilot started as a school project with a clear constraint: build something that actually works the way a team works. Not a demo, not a mockup. The goal was a real tool you could hand to a team and have them use on day one without a manual. That constraint drove every decision: keep the interface clean, keep the features purposeful, and cut anything that does not pull its weight.</p></section><section class="about-section" data-v-ea78cb96><h2 data-v-ea78cb96>What it is</h2><p data-v-ea78cb96>At its core, TaskPilot is a kanban-based workspace. You create a project, set up groups that match your workflow, and fill them with task cards. Each task can carry a label, a priority level, a deadline, and a running comment thread. When a task needs attention, the team gets notified inside the app.</p><p class="para-spaced" data-v-ea78cb96>Projects have member roles so the right people have the right access. Any board can also be shared as a read-only public link, so stakeholders can follow along without needing an account. Tasks that are not ready for the board live in the backlog until they are.</p></section>',3)),a("section",v,[e[0]||(e[0]=a("h2",null,"What is in it",-1)),a("div",m,[(c(),s(h,null,b(l,t=>a("div",{class:"feature-row",key:t.label},[a("span",k,n(t.label),1),a("span",g,n(t.desc),1)])),64))])]),e[2]||(e[2]=o('<section class="about-section" data-v-ea78cb96><h2 data-v-ea78cb96>Roles and permissions</h2><div class="role-grid" data-v-ea78cb96><div class="role-card" data-v-ea78cb96><h3 data-v-ea78cb96>Owner</h3><p data-v-ea78cb96>Full control. Can manage members, change settings, and delete the project.</p></div><div class="role-card" data-v-ea78cb96><h3 data-v-ea78cb96>Admin</h3><p data-v-ea78cb96>Can manage members and settings. Cannot delete the project.</p></div><div class="role-card" data-v-ea78cb96><h3 data-v-ea78cb96>User</h3><p data-v-ea78cb96>Can create and manage tasks within the board.</p></div></div></section><section class="about-section" data-v-ea78cb96><h2 data-v-ea78cb96>Public access</h2><p data-v-ea78cb96>No account is needed to view the homepage, about, or contact pages. Any project shared via a public link is also viewable without logging in, in read-only mode. Everything else requires an account.</p></section><section class="about-section" data-v-ea78cb96><h2 data-v-ea78cb96>The goal</h2><p data-v-ea78cb96>Ship a focused tool that teams can actually stick with. No feature creep, no dashboard bloat. Just the right tools, built well.</p></section>',3))])]))}},T=i(w,[["__scopeId","data-v-ea78cb96"]]);export{T as default};
